div.script:
function addParticipantRow() {
    var tbody = document.getElementById('tn_rows');
    var rows = tbody.querySelectorAll('.tn-row');
    var nr = rows.length + 1;
    var row = document.createElement('tr');
    row.className = 'tn-row';
    row.innerHTML =
        '<td class="tn-nr">' + nr + '</td>' +
        '<td><input type="text" name="tn_name_' + nr + '" class="form-control form-control-sm"/></td>' +
        '<td><input type="date" name="tn_birth_' + nr + '" class="form-control form-control-sm"/></td>' +
        '<td><input type="text" name="tn_zip_' + nr + '" class="form-control form-control-sm" style="width:80px"/></td>' +
        '<td><input type="text" name="tn_city_' + nr + '" class="form-control form-control-sm"/></td>' +
        '<td class="text-center"><input type="checkbox" name="tn_leader_' + nr + '" class="form-check-input"/></td>' +
        '<td class="text-center"><input type="checkbox" name="tn_juleica_' + nr + '" class="form-check-input"/></td>' +
        '<td><button type="button" class="btn btn-sm btn-outline-danger" onclick="removeParticipantRow(this)"><i class="fa fa-trash"></i></button></td>';
    tbody.appendChild(row);
}
function removeParticipantRow(btn) {
    var row = btn.closest('tr');
    row.remove();
    var rows = document.querySelectorAll('#tn_rows .tn-row');
    rows.forEach(function(r, i) { r.querySelector('.tn-nr').textContent = i + 1; });
}
